import play.api.mvc._
import play.api.libs.json._
import scala.concurrent.ExecutionContext
import slick.jdbc.PostgresProfile.api._
import scala.concurrent.Future

case class Product(id: Int, name: String, price: Double, category: String)

class ProductController @javax.inject.Inject() (
  val controllerComponents: ControllerComponents,
  db: Database
)(implicit ec: ExecutionContext) extends BaseController {

  def searchProducts() = Action.async { implicit request =>
    val nameFilter = request.queryString.get("name").flatMap(_.headOption)
    val categoryFilter = request.queryString.get("category").flatMap(_.headOption)
    val minPrice = request.queryString.get("minPrice").flatMap(_.headOption)
    val maxPrice = request.queryString.get("maxPrice").flatMap(_.headOption)
    
    val sqlFragment = buildWhereClause(nameFilter, categoryFilter, minPrice, maxPrice)
    
    val query = sql"SELECT * FROM products WHERE $sqlFragment".as[Product]
    
    db.run(query).map(products => Ok(Json.toJson(products)))
  }
  
  private def buildWhereClause(nameFilter: Option[String], categoryFilter: Option[String], minPrice: Option[String], maxPrice: Option[String]): SqlNode = {
    val conditions = List(
      nameFilter.map(_ => "name ILIKE '%' || ${nameFilter.get} || '%'"),
      categoryFilter.map(_ => "category = ${categoryFilter.get}"),
      minPrice.map(_ => "price >= ${minPrice.get}"),
      maxPrice.map(_ => "price <= ${maxPrice.get}")
    ).flatten
    
    if (conditions.isEmpty) {
      sql"1=1"
    } else {
      sql"(${conditions.mkString(" AND ")})"
    }
  }
